// Processar payload do webhook Hotmart
const body = $input.first().json.body || $input.first().json;

// Estrutura do webhook Hotmart
const event = body.event || '';
const data = body.data || {};

// Só processar compras aprovadas
const eventosValidos = ['PURCHASE_COMPLETE', 'PURCHASE_APPROVED', 'PURCHASE_BILLET_PRINTED'];
if (!eventosValidos.includes(event)) {
  return []; // ignorar outros eventos
}

const purchase = data.purchase || {};
const buyer = data.buyer || {};
const product = data.product || {};

const valor = purchase.price?.value || 27.00;
const moeda = purchase.price?.currency_value || 'BRL';
const pagamento = purchase.payment?.type || 'Desconhecido';
const status = purchase.status || '';
const transactionId = purchase.transaction || '';

// Nome do comprador (só primeiro nome + inicial do sobrenome por privacidade)
const nomeCompleto = buyer.name || 'Comprador';
const partesNome = nomeCompleto.trim().split(' ');
const nomeExibido = partesNome.length > 1
  ? `${partesNome[0]} ${partesNome[partesNome.length-1][0]}.`
  : partesNome[0];

// Método de pagamento formatado
const metodos = {
  'CREDIT_CARD': '💳 Cartão de Crédito',
  'BILLET': '📄 Boleto',
  'PIX': '⚡ Pix',
  'PAYPAL': '🅿️ PayPal',
  'GOOGLE_PAY': '🟢 Google Pay'
};
const metodoPagamento = metodos[pagamento] || pagamento;

// Data e hora
const agora = new Date();
const hora = agora.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
const data_str = agora.toLocaleDateString('pt-BR');

// Emoji por status
const statusEmoji = event === 'PURCHASE_COMPLETE' || event === 'PURCHASE_APPROVED' ? '🎉' : '⏳';
const statusTxt = event === 'PURCHASE_COMPLETE' || event === 'PURCHASE_APPROVED' ? 'VENDA CONFIRMADA' : 'BOLETO GERADO';

const mensagem = `${statusEmoji} ${statusTxt} — Empresa Protegida™
` +
  `📅 ${data_str} às ${hora}

` +
  `💰 Valor: R$${parseFloat(valor).toFixed(2)}
` +
  `👤 Comprador: ${nomeExibido}
` +
  `${metodoPagamento}
` +
  `🔖 ID: ${transactionId.slice(-8)}

` +
  `🛡️ Vai lá e faz!`;

return [{ json: { mensagem } }];
